е…¶е®һеңЁеҶҷеҮҪж•°зҡ„ж—¶еҖҷпјҢжҲ‘д»¬д№ҹеҸҜд»ҘеҲ©з”ЁйҖ’еҪ’жҖқжғіпјҢд№ҹе°ұжҳҜеҲҶжІ»жі•жқҘдјҳеҢ–д»Јз ҒпјҢеҗҢж ·жқҘиҮӘDavidпјҢдҫӢеҰӮжҲ‘д»¬иҰҒеҶҷдёҖдёӘжү“еҚ°MarioйҮҢзҡ„з –еқ—пјҲйҳ¶жўҜеһӢпјүзҡ„еҮҪж•°пјҢжҲ‘д»¬еҸҜд»Ҙиҝҷж ·жҖқиҖғпјҡжҜҸж¬Ўжү“еҚ°дёӢдёҖеұӮж—¶пјҢе…¶е®һе°ұжҳҜжҜ”дёҠдёҖеұӮз –еқ—еӨҡдәҶдёҖдёӘз –еқ—гҖӮи®©жҲ‘д»¬жқҘзңӢзңӢдёӢйқўзҡ„д»Јз ҒгҖӮ
```C
void draw(int n)
{
    if (n <= 0)
    {
        return;
    }

    draw(n - 1);

    for (int i = 0; i < n; i++)
    {
        printf("#");
    }
    printf("\n");
}
```

