## еҸҢжҢҮй’Ҳ&иҙӘеҝғз®—жі•
иҝҷйҒ“йўҳжҲ‘д»¬еҸҜд»ҘдҪҝз”ЁеҸҢжҢҮй’Ҳзҡ„ж–№жі•пјҢи®©е·ҰеҸіжҢҮй’ҲеҲҶеҲ«жҢҮеҗ‘ж•°з»„зҡ„е·ҰеҸідёӨз«ҜпјҢд»ҺиҖҢеҸҜд»ҘиЎЁзӨәе®№еҷЁзҡ„е·ҰеҸій«ҳеәҰд»ҘеҸҠе®ҪеәҰгҖӮ
з„¶еҗҺж №жҚ®иҙӘеҝғз®—жі•зҡ„жҖқжғіпјҢжҜҸж¬Ўеҗ‘дёӯй—ҙз§»еҠЁжңҖдҪҺзҡ„зҡ„жҹұеӯҗпјҢи®°еҪ•ж°ҙйҮҸпјҢзӯүе·ҰеҸіжҢҮй’ҲзӣёйҒҮеҲҷеҒңжӯўгҖӮ

## д»Јз Ғе®һзҺ°
```
class Solution {
public:
    int maxArea(vector<int>& height) {
        int n = height.size()-1;
        int i = 0, j = n;
        int sum = 0;
        while(i < j){
            int len = j - i;
            int cur = len * min(height[i], height[j]);
            if(cur > sum){
                sum = cur;
            }
            if(height[i] < height[j]){
                i++;
            }
            else{
                j--;
            }
        }
        return sum;
    }
};
```

