```

### жҖқи·Ҝ

жіЁж„ҸеҲ°йўҳзӣ®иҜҙдәҶпјҢжүҖжңүйҮ‘еёҒйғҪеҸҜд»ҘйҡҸж„ҸеҲҶеүІпјҢеҲҶеүІе®Ңзҡ„йҮ‘еёҒйҮҚйҮҸд»·еҖјжҜ”дёҚеҸҳгҖӮеӣ жӯӨпјҢжҲ‘д»¬еҸҜд»Ҙе…ҲеҜ№йҮ‘еёҒжҢүз…§д»·еҖјд»Һе°ҸеҲ°еӨ§жҺ’еәҸпјҢз„¶еҗҺд»ҺеҗҺеҫҖеүҚйҒҚеҺҶпјҲдёәд»Җд№ҲдёҚд»ҺеӨ§еҲ°е°ҸжҺ’еәҸе‘ўпјҹеӣ дёәsort()еҮҪж•°й»ҳи®ӨжҳҜд»Һе°ҸеҲ°еӨ§жҺ’еәҸзҡ„пјҢжҲ‘жҜ”иҫғжҮ’пјүпјҢеҰӮжһңеҪ“еүҚзҡ„йҮ‘еёҒзҡ„йҮҚйҮҸе°ҸдәҺзӯүдәҺиғҢеҢ…зҡ„е®№йҮҸпјҢжҲ‘д»¬е°ұжҠҠе®ғиЈ…иҝӣеҺ»пјҢе№¶жӣҙж–°иғҢеҢ…зҡ„е®№йҮҸе’Ңд»·еҖјгҖӮеҰӮжһңеҪ“еүҚзҡ„йҮ‘еёҒзҡ„йҮҚйҮҸеӨ§дәҺиғҢеҢ…зҡ„е®№йҮҸпјҢжҲ‘д»¬е°ұеҒңжӯўиЈ…дәҶпјҢеӣ дёәиЈ…дёҚдёӢдәҶгҖӮ

иҝҷйҮҢжҲ‘д»¬дҪҝз”Ёз»“жһ„дҪ“жқҘжү“еҢ…йҮ‘еёҒзҡ„дҝЎжҒҜпјҢеҢ…жӢ¬йҮҚйҮҸе’Ңд»·еҖјд»ҘеҸҠжҖ§д»·жҜ”гҖӮ
з„¶еҗҺиҰҒеҶҷдёҖдёӘжҺ’еәҸеҮҪж•°жқҘе‘ҠиҜүsort()еҮҪж•°жҲ‘д»¬иҰҒжҢүз…§з»“жһ„дҪ“дёӯзҡ„д»·еҖјиҝӣиЎҢжҺ’еәҸгҖӮ
```c++
struct Item {
    int weight;
    int value;
    double ratio;
};

bool cmp(Item a, Item b) {
    return a.ratio > b.ratio;
}
```
ж„ҹи§үиҝҷдёҖжӯҘеә”иҜҘжҳҜжңҖе…ій”®зҡ„пјҢд№ҹжҳҜжңҖйә»зғҰзҡ„пјҲеҜ№дәҺдёҖдёӘrookieжқҘиҜҙпјүгҖӮ

### е®Ңж•ҙд»Јз Ғ

```c++
#include <bits/stdc++.h>
using namespace std;

struct Item {
    int weight;
    int value;
    double ratio;
};

bool cmp(Item a, Item b) {
    return a.ratio > b.ratio;
}

int main() {
    int N, T;
    cin >> N >> T;
    vector<Item> items(N);
    for (int i = 0; i < N; i++) {
        cin >> items[i].weight >> items[i].value;
        items[i].ratio = (double)items[i].value / items[i].weight;
    }
    sort(items.begin(), items.end(),cmp);
    double total = 0.0;
    for (int i = 0; i < N && T > 0; i++) {
        if (items[i].weight <= T) {
            total += items[i].value;
            T -= items[i].weight;
        } else {
            total += items[i].ratio * T;
            T = 0;
        }
    }
    printf("%.2f\n", total);
    return 0;
}
```

