    double ratio;
};

bool cmp(Item a, Item b) {
    return a.ratio > b.ratio;
}

int main() {
    int N, T;
    cin >> N >> T;
    vector<Item> items(N);
    for (int i = 0; i < N; i++) {
        cin >> items[i].weight >> items[i].value;
        items[i].ratio = (double)items[i].value / items[i].weight;
    }
    sort(items.begin(), items.end(),cmp);
    double total = 0.0;
    for (int i = 0; i < N && T > 0; i++) {
        if (items[i].weight <= T) {
            total += items[i].value;
            T -= items[i].weight;
        } else {
            total += items[i].ratio * T;
            T = 0;
        }
    }
    printf("%.2f\n", total);
    return 0;
}
